mapper.select:
select a.YYYYMM, a.SEL_CODE, CASE WHEN a.SITE='HQ' then '본사' WHEN a.site='VN' then 'VINA' else a.site end SITE, CASE WHEN ACCT_CLASS='AA' then '가공비' WHEN ACCT_CLASS='CC' then '판매관리비' WHEN ACCT_CLASS='BB' then '개발비' else ACCT_CLASS end as ACCT_CLASS, --a.dept, b.dept_name, a.SUB_NAME, a.ITEM_NAME, sum(a.ACCT_AMT) ACCT_AMT, a.EXPEN_SEL from doi_acct_expen a left join doi_dept b on (b.yyyy=substring(a.yyyymm,1,4) and b.sel_code=a.sel_code and b.site=a.site and b.dept=a.dept) where 1=1 and a.EXPEN_SEL not like 'M%'
and a.YYYYMM = #{yyyymm}
and a.SITE = #{site}
and a.ACCT_CLASS = #{costGubun}
AND a.ACCT_CLASS='AA' AND a.EXPEN_SEL NOT LIKE 'M%'
AND a.ACCT_CLASS='AA' AND a.EXPEN_SEL LIKE 'X%'
group by a.YYYYMM, a.SEL_CODE, CASE WHEN a.SITE='HQ' then '본사' WHEN a.site='VN' then 'VINA' else a.site end, CASE WHEN ACCT_CLASS='AA' then '가공비' WHEN ACCT_CLASS='CC' then '판매관리비' WHEN ACCT_CLASS='BB' then '개발비' else ACCT_CLASS end, --a.dept, b.dept_name, a.SUB_NAME, a.ITEM_NAME, a.EXPEN_SEL
union all select YYYYMM, SEL_CODE, SITE, '재료비', '제조공통', CASE WHEN MAT_CLASS='원자재' then '직접재료비' else '간접재료비' end, MAT_CLASS, sum(IN_AMT) 금액, CASE WHEN MAT_CLASS='원자재' then 'MDAX' else ' MIAX' end from doi_material_resc where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
group by YYYYMM, SEL_CODE, SITE, MAT_CLASS HAVING sum(IN_AMT) > 0
order BY 1,2,3,4,5,6,7,8;

select YYYYMM, SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN site='VN' then 'VINA' else site end SITE, SUB_NAME, ITEM_NAME, SUM(ACCT_AMT) ACCT_AMT, EXPEN_SEL from DOI_ACCT_EXPEN where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
and acct_class = 'AA' GROUP BY YYYYMM,SEL_CODE,SITE,SUB_NAME,ITEM_NAME,EXPEN_SEL order by SUB_NAME,ITEM_NAME;

select a.YYYYMM, a.SEL_CODE, CASE WHEN a.SITE='HQ' then '본사' WHEN a.SITE='VN' then 'VINA' else a.SITE end SITE, CASE WHEN a.ACCT_CLASS='AA' then '가공비' WHEN a.ACCT_CLASS='CC' then '판매관리비' WHEN a.ACCT_CLASS='BB' then '개발비' else a.ACCT_CLASS end as ACCT_CLASS , b.DEPT_NAME, SUB_NAME, ITEM_NAME, SUM(ACCT_AMT) ACCT_AMT, EXPEN_SEL from DOI_ACCT_EXPEN a inner join doi_dept b on(a.dept=b.dept) where 1=1
and a.YYYYMM = #{yyyymm}
and a.SITE = #{site}
and a.EXPEN_SEL = #{expenSel}
group by a.YYYYMM, a.SEL_CODE, CASE WHEN a.SITE='HQ' then '본사' WHEN a.site='VN' then 'VINA' else a.SITE end, CASE WHEN a.ACCT_CLASS='AA' then '가공비' WHEN a.ACCT_CLASS='CC' then '판매관리비' WHEN a.ACCT_CLASS='BB' then '개발비' else a.ACCT_CLASS end, b.DEPT_NAME,SUB_NAME,ITEM_NAME,EXPEN_SEL order by SUB_NAME,ITEM_NAME;

select YYYYMM, SEL_CODE, DW_SITE as SITE, 구분, 도우모델 as MODEL, MODEL_N_TYPE, sum(BOH_MONTH) as BOH_MONTH, sum(IN_MONTH) as IN_MONTH, sum(BONUS_MONTH) as BONUS_MONTH, sum(EOH_MONTH) as EOH_MONTH, sum(OUT_MONTH) as OUT_MONTH, sum(LOSS_MONTH) as LOSS_MONTH, sum(NG_MONTH) as NG_MONTH, sum(수율제외_MONTH) as 수율제외_MONTH, sum(REWORK진행_MONTH) as REWORK진행_MONTH, sum(material_loss) as material_loss from DOI_PROD_SUBUL where 1=1
and YYYYMM = #{yyyymm}
and DW_SITE = #{site}
and 구분 = #{prodGubun}
group by YYYYMM,SEL_CODE,DW_SITE,구분,도우모델,MODEL_N_TYPE order by 1,2,3,model, MODEL_N_TYPE;

select lotrun_no,BOH_MONTH,IN_MONTH,BONUS_MONTH,EOH_MONTH,OUT_MONTH,LOSS_MONTH,NG_MONTH,
수율제외_MONTH,REWORK진행_MONTH,material_loss
from DOI_PROD_LOTRUN
where 1=1

    and YYYYMM = #{yyyymm}


    and DW_SITE = #{site}


    and 구분 = #{prodGubun}


    and MODEL_N_TYPE = #{modelNType}

order by lotrun_no;

select YYYYMM, sel_code, CASE WHEN SITE='HQ' then '본사' WHEN site='VN' then 'VINA' end AS SITE, 구분, model, 면적, dist_rate, SUB_NAME, ITEM_NAME, EXPEN_SEL, EXPEN_SEL명, adj_qty, in_qty, out_qty, loss_qty, unit_cost, [in] as input_Amt from doi_expen_matl where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
order by YYYYMM,SEL_CODE,SITE,MODEL;

select YYYYMM, SEL_CODE, SITE, 구분, MODEL, BOH, [IN] INPUT_AMT, ACCT_NAME , SUB_NAME , ITEM_NAME from doi_expen_matl where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
and MODEL = #{model}
order by 구분,EXPEN_SEL;

select YYYYMM, SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN site='VN' then 'VINA' end AS SITE, MAT_CLASS, CASE WHEN MAT_CLASS='원자재' THEN 'MDAX' ELSE 'MIAX' end as expen_sel, CASE WHEN MAT_CLASS='원자재' THEN '직접재료비' ELSE '간접재료비' end as expen_sel명, MAT_CODE, MAT_DESC, SUM(IN_QTY) IN_QTY, AVG(UNIT_COST) UNIT_COST, SUM(IN_AMT) IN_AMT from DOI_MATERIAL_RESC where 1=1 and sel_code = 'ACTUAL'
and YYYYMM = #{yyyymm}
and SITE = #{site}
group by YYYYMM, SEL_CODE, SITE, MAT_CLASS, MAT_CODE, MAT_DESC having sum(in_amt) > 0 order by 5,7;

select YYYYMM, SEL_CODE, SITE, MAT_CODE, MST_DESC, [SIZE], IN_QTY, UNIT_COST, IN_AMT, COST_GUBUN, MAT_CLASS, MODEL, MODEL_N_TYPE FROM DOI_MATERIAL_RESC where 1=1 and sel_code = 'ACTUAL'
and YYYYMM = #{yyyymm}
and SITE = #{site}
and mat_class = #{matClass}
order by 1,2,3,4;

WITH BOM as ( SELECT * FROM ( select b.yyyymm, b.자재번호, b.자재명, b.자재대분류, row_number() over (partition by b.자재번호 order by (b.자재대분류)) rn1 from doi_bom_mast b where 1=1 and yyyymm = #{yyyymm} and site = #{site} and nullif(자재번호, '') IS NOT NULL
)a where rn1=1 ) select a.yyyymm, a.sel_code, CASE WHEN a.SITE='HQ' then '본사' WHEN a.site='VN' then 'VINA' end AS SITE, a.도우모델, a.자재번호, b.자재명, case when a.mat_class='원자재' then 'MDAX' else 'MIDX' end as expen_sel, case when a.mat_class='원자재' then '직접재료비' else '간접재료비' end as expen_sel명, a.mat_class, --a.자재대분류, a.in_amt, a.환산량, CASE WHEN 배부방식='BOM' THEN a.소요량 ELSE NULL END AS BOM사용량, CASE WHEN 배부방식!='BOM' THEN a.소요량 ELSE NULL END AS 면적, a.사용량, a.배부적수, a.배부금액, a.배부방식 from doi_mat_cost a left join bom b on (a.자재번호 = b.자재번호) where 1=1
and A.YYYYMM = #{yyyymm}
and A.SITE = #{site}
order by a.배부방식 desc,a.자재번호

select *
from doi_mat_cost
where 1=1

    and YYYYMM = #{yyyymm}


    and SITE = #{site}


    and mat_class = #{matClass}

order by 1,2,3,4,5,6;

select yyyymm,sel_code,site,도우모델,sum(배부금액) 배부금액
from doi_mat_cost
where 1=1

    and YYYYMM = #{yyyymm}


    and SITE = #{site}

group by yyyymm,sel_code,site,도우모델
order by 도우모델;

select *
from doi_mat_cost
where 1=1

    and YYYYMM = #{yyyymm}


    and SITE = #{site}


    and 도우모델 = #{model}

order by 1,2,3,4,5,6,7;

select YYYYMM, SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN SITE='VN' then 'VINA' else SITE end SITE, 구분, MODEL, EXPEN_SEL, ACCT_NAME, SUB_NAME, ITEM_NAME, SUM(BOH) BOH, SUM([IN]) INPUT_AMT, SUM(EOH) EOH, SUM([OUT]) OUT_AMT, SUM(LOSS) LOSS from doi_cost where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
and SUB_NAME LIKE '%' + #{acctName}
GROUP BY YYYYMM,SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN SITE='VN' then 'VINA' else SITE end, 구분,MODEL,EXPEN_SEL,ACCT_NAME,SUB_NAME,ITEM_NAME order BY 1,2,3,4,5,6,7,8;

select YYYYMM, SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN SITE ='VN' then 'VINA' else SITE end SITE, MODEL, STOCK, SUM(BOH) BOH, SUM([INPUT]) IN_QTY, SUM([OUT]) OUT_QTY, SUM(EOH) EOH from doi_stock where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
GROUP BY YYYYMM, SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN SITE='VN' then 'VINA' else SITE end, MODEL, STOCK ORDER BY 1,2,3,4

select YYYYMM, SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN SITE='VN' then 'VINA' else SITE end SITE, 구분, MODEL, BOH_AMT, IN_AMT, EOH_AMT, OUT_AMT from doi_stock_cost where 1=1 and sel_code = 'ACTUAL'
and YYYYMM = #{yyyymm}
and SITE = #{site}
and 구분 = #{gubun}
and BOH_AMT+IN_AMT+EOH_AMT+OUT_AMT > 0 order BY 1,2,3,4,5;
